import random
from store import insert, exists, get


def write_record(key, value):
    if random.random() < 0.3:
        raise ConnectionError("transient write failure")
    return insert(key, value)


def safe_write(key, value):
    if exists(key):
        return get(key)
    return insert(key, value)


def write_with_retry(key, value, max_retries=3):
    # Idempotency guard: if the key already exists, return its seq.
    if exists(key):
        item = get(key)
        return item["seq"]

    for attempt in range(max_retries):
        try:
            seq = write_record(key, value)
            return seq
        except ConnectionError:
            # It's possible that a transient failure still left the insert in place
            # (e.g. if write_record implementation changes). Check and return if present.
            if exists(key):
                return get(key)["seq"]
            # otherwise, retry
            continue

    # Final check before giving up to avoid duplicating an insert on a last-moment success
    if exists(key):
        return get(key)["seq"]

    raise ConnectionError(f"failed after {max_retries} retries")
