def ingest_batch(records, max_batch_retries=3):
    """
    Attempt to apply the entire batch up to max_batch_retries times.
    On any per-record ultimate failure, rollback (clear) partial effects and retry the whole batch.
    This ensures either the whole batch (in order) is applied, or no partial effects remain.
    """
    for batch_attempt in range(max_batch_retries):
        # start each attempt from a clean state
        clear()
        results = []
        try:
            for r in records:
                seq = write_with_retry(r["key"], r["value"])
                results.append({"key": r["key"], "seq": seq})
            # success: return results and final seq
            return {"results": results, "final_seq": get_seq()}
        except ConnectionError:
            # rollback and retry entire batch
            clear()
            if batch_attempt == max_batch_retries - 1:
                # final failure: propagate
                raise
            # otherwise, continue to next batch attempt
            continue


def ingest_safe(records):
    clear()
    results = []
    for r in records:
        seq = safe_write(r["key"], r["value"])
        results.append({"key": r["key"], "seq": seq})
    return {"results": results, "final_seq": get_seq()}
